// Step 1: Extract audio from video using FFmpeg (via shell command or external service)
// Input: video file path or URL from webhook
const inputData = $input.first().json.body;
const videoPath = inputData.video_path || inputData.video_url;
const outputDir = inputData.output_dir || '/tmp/video_pipeline';
const jobId = Date.now().toString();

if (!videoPath) {
  throw new Error('Missing video_path or video_url in request body');
}

return [{
  json: {
    job_id: jobId,
    video_path: videoPath,
    output_dir: `${outputDir}/${jobId}`,
    audio_output_path: `${outputDir}/${jobId}/audio.mp3`,
    status: 'initialized'
  }
}];

const allItems = $input.all();

return allItems.map(item => ({
  json: {
    ...item.json,
    whisper_model: 'whisper-1',
    response_format: 'verbose_json',
    status: 'audio_extracted'
  }
}));

const allChunks = $('Extract Audio Chunk').all();

return allChunks.map(chunk => ({
  json: {
    ...chunk.json,
    chunk_index: chunk.json.chunk_index
  },
  binary: {
    data: {
      data: chunk.json.audio_base64,
      mimeType: 'audio/mpeg',
      fileName: `chunk_${chunk.json.chunk_index}.mp3`
    }
  }
}));

const jobData = $('Initialize Job').first().json;
const totalDuration = $input.first().json.duration;
const CHUNK_DURATION = 300;

const chunks = [];
let start = 0;
let chunkIndex = 0;

while (start < totalDuration) {
  chunks.push({
    ...jobData,
    chunk_index: chunkIndex,
    start_time: start,
    chunk_duration: Math.min(CHUNK_DURATION, totalDuration - start),
    audio_chunk_path: `${jobData.output_dir}/chunks/chunk_${chunkIndex}.mp3`,
    total_duration: totalDuration
  });
  start += CHUNK_DURATION;
  chunkIndex++;
}

return chunks.map(chunk => ({ json: chunk }));

const input = $input.first().json;

// Handle both array and single item
const allChunks = Array.isArray(input.data) ? input.data : Object.values(input).filter(v => typeof v === 'object' && v !== null && 'text' in v);

const sortedChunks = allChunks.sort((a, b) => (a.chunk_index ?? 0) - (b.chunk_index ?? 0));

let mergedSegments = [];
let fullText = '';
let timeOffset = 0;

for (const chunk of sortedChunks) {
  const segments = chunk.segments || [];
  const chunkDuration = chunk.chunk_duration || 300;

  mergedSegments = mergedSegments.concat(
    segments.map(seg => ({
      ...seg,
      start: seg.start + timeOffset,
      end: seg.end + timeOffset
    }))
  );

  fullText += ' ' + (chunk.text || '');
  timeOffset += chunkDuration;
}

return [{
  json: {
    ...$('Initialize Job').first().json,
    segments: mergedSegments,
    text: fullText.trim(),
    total_chunks: sortedChunks.length
  }
}];

const whisperResponse = $input.first().json;
const jobData = $('Initialize Job').first().json;

const segments = whisperResponse.segments || [];

if (segments.length === 0) {
  throw new Error('No segments found in Whisper response');
}

const SCENE_DURATION_THRESHOLD = 300;
const scenes = [];
let currentScene = {
  scene_index: 0,
  start_time: segments[0].start,
  end_time: segments[0].end,
  original_text: segments[0].text,
  segments: [segments[0]]
};

for (let i = 1; i < segments.length; i++) {
  const seg = segments[i];
  const sceneDuration = seg.end - currentScene.start_time;

  if (sceneDuration > SCENE_DURATION_THRESHOLD) {
    currentScene.duration = currentScene.end_time - currentScene.start_time;
    scenes.push(currentScene);
    currentScene = {
      scene_index: scenes.length,
      start_time: seg.start,
      end_time: seg.end,
      original_text: seg.text,
      segments: [seg]
    };
  } else {
    currentScene.end_time = seg.end;
    currentScene.original_text += ' ' + seg.text;
    currentScene.segments.push(seg);
  }
}

currentScene.duration = currentScene.end_time - currentScene.start_time;
scenes.push(currentScene);

return scenes.map(scene => ({
  json: {
    ...jobData,
    scene,
    total_scenes: scenes.length,
    full_transcript: whisperResponse.text
  }
}));

