      "role": "user",
      "content": "Scene {{ $json.scene.scene_index + 1 }} of {{ $json.total_scenes }}\nOriginal duration: {{ $json.scene.duration.toFixed(2) }} seconds\nOriginal text: {{ $json.scene.original_text }}\n\nGenerate the narration. Return only valid JSON."
    }
  ],
  "response_format": { "type": "json_object" },
  "temperature": 0.7
}

