const allGptResponses = $input.all();
const allScenes = $('Split into Scenes1').all();
const jobData = $('Initialize Job').first().json;

return allGptResponses.map((gptItem, index) => {
  let narrationData;
  try {
    const content = gptItem.json.choices[0].message.content;
    narrationData = typeof content === 'string' ? JSON.parse(content) : content;
  } catch (e) {
    throw new Error('Failed to parse GPT narration response: ' + e.message);
  }

  const scene = allScenes[index].json.scene;

  return {
    json: {
      ...jobData,
      scene: {
        ...scene,
        original_subtitle: narrationData.original_subtitle || scene.original_text,
        narration_text: narrationData.narration,
        estimated_narration_duration: narrationData.estimated_duration_seconds
      },
      narration_text: narrationData.narration,
      total_scenes: allScenes.length,
      tts_voice: 'alloy',
      tts_model: 'tts-1-hd'
    }
  };
});
